css:
.table{
    margin:0px !important;
}
.print-format td, .print-format th {
    padding: 3px !important;
}
.table-bordered tbody{
    border-color: #333c44 !important;
}


* {
    -webkit-print-color-adjust: exact !important;
    color-adjust: exact !important;
    box-sizing: border-box;
}

body, html {
    font-family: 'Cairo', 'Arial', 'Helvetica', sans-serif !important;
    /*font-weight: 400;*/
    color: #000000 !important;
    background: #ffffff !important;
    margin: 0;
    padding: 0;
    line-height: 1.4;
}

/* Ensure all text elements use Cairo font for consistency */
h1, h2, h3, h4, h5, h6, p, div, span, td, th, li, a, 
.text-center, .text-left, .text-right {
    font-family: 'Cairo', 'Arial', 'Helvetica', sans-serif !important;
    color: #000000 !important;
}

@media print {
    body, html {
        font-family: 'Cairo', 'Arial', sans-serif !important;
        background: white !important;
        color: black !important;
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
    }

    .page-break {
        page-break-before: always;
        background: white !important;
        color: black !important;
    }

    .hidden-pdf {
        display: none !important;
    }

    .visible-pdf {
        display: block !important;
    }

    /* Ensure tables print correctly */
    table {
        border-collapse: collapse !important;
    }

    th, td {
        background: white !important;
        color: black !important;
    }
}
